patch:
--- a/comparator.sv
+++ b/comparator.sv
@@ -1,12 +1,12 @@
 module comparator_64bit(
   input [63:0] data_x, data_y,
   input enable,
   output reg eq, lt, gt
 );

-  always @(data_x or data_y)
+  always @(data_x or data_y or enable)
     if (enable)
       begin
         eq = (data_x == data_y);
         lt = (data_x < data_y);
         gt = (data_x > data_y);
       end

before_code:
module comparator_64bit(
  input [63:0] data_x, data_y,
  input enable,
  output reg eq, lt, gt
);

  always @(data_x or data_y)
    if (enable)
      begin
        eq = (data_x == data_y);
        lt = (data_x < data_y);
        gt = (data_x > data_y);
      end
    else
      begin
        eq = 1'b0;
        lt = 1'b0;
        gt = 1'b0;
      end

endmodule

after_code:
